mapper.select:
/* SQL ID: www.api.mmp.map.Map.selectMapList Description : 목록 Query */ SELECT MAP_IDX ,TITLE ,MAP_GRP_IDX ,MAP_NM ,CONTENT ,LAT ,LNG ,CREATE_USER ,DATE_FORMAT(CREATE_DATE, '%Y-%m-%d %H:%i:%s') AS CREATE_DATE ,UPDATE_USER ,DATE_FORMAT(UPDATE_DATE, '%Y-%m-%d %H:%i:%s') AS UPDATE_DATE
FROM map
ORDER BY MAP_IDX DESC
/* 페이징 하단 시작 */ LIMIT #{limit} OFFSET #{offset} /* 페이징 하단 끝 */

mapper.insert:
        /*
         SQL ID: www.api.mmp.map.Map.insertMap
         Description : 등록 Query 
        */
        INSERT INTO map
        (
            TITLE
			,MAP_GRP_IDX
			,MAP_NM
			,CONTENT
			,LAT
			,LNG
			,CREATE_USER
			,CREATE_DATE
			,UPDATE_USER
			,UPDATE_DATE

        )
        VALUES
        (
            #{title}
			,#{mapGrpIdx}
			,#{mapNm}
			,#{content}
			,#{lat}
			,#{lng}
			,#{createUser}
			,IFNULL(STR_TO_DATE(#{createDate}, '%Y-%m-%d %H:%i:%s'), NOW())
			,#{updateUser}
			,IFNULL(STR_TO_DATE(#{updateDate}, '%Y-%m-%d %H:%i:%s'), NOW())

        )

mapper.delete:
/*
 SQL ID: www.api.mmp.map.Map.deleteMap
 Description : 삭제 Query 
*/
DELETE FROM map
WHERE MAP_IDX = #{mapIdx}
